1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	interface Incident {
19	  cause: string;
20	  damages: Damage[];
21	}
22	
23	interface ClaimStep {
24	  op: "claim";
25	  policy: number;
26	  incident: Incident;
27	}
28	
29	type Step = QuoteStep | ClaimStep;
30	
31	interface Customer {
32	  yearsWithMHPCO: number;
33	}
34	
35	interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	interface Policy {
41	  items: Item[];
42	  cap: number;
43	  remainingCap: number;
44	}
45	
46	type QuoteResult = { premium: number };
47	type ClaimResult = { payout: number; remainingCap: number };
48	type StepResult = QuoteResult | ClaimResult;
49	
50	const MAIN_ITEM_BASE: Record<string, number> = {
51	  sword: 100,
52	  amulet: 60,
53	  staff: 80,
54	  potion: 40,
55	};
56	
57	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
58	const COMPONENT_BASE = 25;
59	const BLOCK_SIZE = 3;
60	const BLOCK_BASE = 60;
61	
62	const MAIN_ITEM_INSURANCE_VALUE: Record<string, number> = {
63	  sword: 1000,
64	  amulet: 600,
65	  staff: 800,
66	  potion: 400,
67	};
68	const COMPONENT_INSURANCE_VALUE = 250;
69	
70	const DEDUCTIBLE = 100;
71	const CAP_MULTIPLIER = 2;
72	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
73	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
74	
75	const PROCESSING_FEE = 5;
76	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
77	const CURSED_SURCHARGE_RATE = 0.5;
78	const HIGH_ENCHANTMENT_THRESHOLD = 5;
79	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
80	const LOYALTY_THRESHOLD_YEARS = 2;
81	const LOYALTY_DISCOUNT_RATE = 0.2;
82	const FOLLOWUP_DISCOUNT_RATE = 0.15;
83	
84	const componentGroupBase = (count: number): number => {
85	  if (count === BLOCK_SIZE) return BLOCK_BASE;
86	  return count * COMPONENT_BASE;
87	};
88	
89	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
90	
91	const mainItems = (items: Item[]): Item[] => items.filter((item) => !isComponent(item));
92	
93	const sumMainItems = (items: Item[]): number =>
94	  mainItems(items).reduce((total, item) => total + MAIN_ITEM_BASE[item.type], 0);
95	
96	const countByType = (items: Item[]): Record<string, number> => {
97	  const counts: Record<string, number> = {};
98	  for (const item of items) {
99	    counts[item.type] = (counts[item.type] ?? 0) + 1;
100	  }
101	  return counts;
102	};
103	
104	const sumComponentGroups = (items: Item[]): number => {
105	  const counts = countByType(items.filter(isComponent));
106	  return Object.values(counts).reduce((total, count) => total + componentGroupBase(count), 0);
107	};
108	
109	const policyBasePremium = (items: Item[]): number =>
110	  sumMainItems(items) + sumComponentGroups(items);
111	
112	const cursedSurcharge = (item: Item): number => {
113	  const base = MAIN_ITEM_BASE[item.type];
114	  return item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
115	};
116	
117	const highEnchantmentSurcharge = (item: Item): number => {
118	  const base = MAIN_ITEM_BASE[item.type];
119	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
120	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
121	    : 0;
122	};
123	
124	const itemSurcharges = (items: Item[]): number =>
125	  mainItems(items).reduce(
126	    (total, item) => total + cursedSurcharge(item) + highEnchantmentSurcharge(item),
127	    0,
128	  );
129	
130	const loyaltyDiscount = (base: number, customer: Customer): number =>
131	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
132	
133	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
134	  isFollowUp ? base * FOLLOWUP_DISCOUNT_RATE : 0;
135	
136	const adjustedPremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
137	  const base = policyBasePremium(items);
138	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
139	  return (
140	    base +
141	    firstInsuranceSurcharge -
142	    loyaltyDiscount(base, customer) -
143	    followUpDiscount(base, isFollowUp) +
144	    itemSurcharges(items)
145	  );
146	};
147	
148	const quotePremium = (step: QuoteStep, customer: Customer, isFollowUp: boolean): number =>
149	  Math.ceil(adjustedPremium(step.items, customer, isFollowUp)) + PROCESSING_FEE;
150	
151	const itemInsuranceValue = (item: Item): number =>
152	  isComponent(item) ? COMPONENT_INSURANCE_VALUE : MAIN_ITEM_INSURANCE_VALUE[item.type];
153	
154	const insuranceSum = (items: Item[]): number =>
155	  items.reduce((total, item) => total + itemInsuranceValue(item), 0);
156	
157	const reimbursedAmount = (amount: number, item: Item | undefined): number =>
158	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
159	    ? amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
160	    : amount;
161	
162	const damagePayout = (damage: Damage, item: Item | undefined): number =>
163	  Math.max(0, reimbursedAmount(damage.amount, item) - DEDUCTIBLE);
164	
165	const insuredItemFor = (policy: Policy, damage: Damage): Item | undefined =>
166	  policy.items.find((item) => item.type === damage.itemType);
167	
168	const requestedPayout = (incident: Incident, policy: Policy): number =>
169	  incident.damages.reduce(
170	    (total, damage) => total + damagePayout(damage, insuredItemFor(policy, damage)),
171	    0,
172	  );
173	
174	const validateDamages = (incident: Incident, policy: Policy): void => {
175	  const unmatched = incident.damages.find((damage) => !insuredItemFor(policy, damage));
176	  if (unmatched) {
177	    throw new Error(`Claim references item not in policy: ${unmatched.itemType}`);
178	  }
179	};
180	
181	const processClaim = (step: ClaimStep, policy: Policy): ClaimResult => {
182	  validateDamages(step.incident, policy);
183	  const requested = requestedPayout(step.incident, policy);
184	  const payout = Math.floor(Math.min(requested, policy.remainingCap));
185	  policy.remainingCap -= payout;
186	  return { payout, remainingCap: policy.remainingCap };
187	};
188	
189	const isKnownItemType = (item: Item): boolean =>
190	  item.type in MAIN_ITEM_BASE || isComponent(item);
191	
192	const validateItems = (items: Item[]): void => {
193	  const unknownItem = items.find((item) => !isKnownItemType(item));
194	  if (unknownItem) {
195	    throw new Error(`Unknown item type: ${unknownItem.type}`);
196	  }
197	};
198	
199	const openPolicy = (step: QuoteStep): Policy => {
200	  validateItems(step.items);
201	  const cap = insuranceSum(step.items) * CAP_MULTIPLIER;
202	  return { items: step.items, cap, remainingCap: cap };
203	};
204	
205	const processQuote = (
206	  step: QuoteStep,
207	  customer: Customer,
208	  isFollowUp: boolean,
209	): QuoteResult => ({ premium: quotePremium(step, customer, isFollowUp) });
210	
211	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
212	  let quoteCount = 0;
213	  const policies: Policy[] = [];
214	  const results = scenario.steps.map((step, index): StepResult => {
215	    if (step.op === "claim") {
216	      return processClaim(step, policies[step.policy]);
217	    }
218	    const isFollowUp = quoteCount > 0;
219	    quoteCount += 1;
220	    policies[index] = openPolicy(step);
221	    return processQuote(step, scenario.customer, isFollowUp);
222	  });
223	  return { results };
224	};
